fun solve(totalSeconds: Int): String {
  val s = if (totalSeconds < 0) 0 else totalSeconds
  val h = s / 3600
  val m = (s % 3600) / 60
  val sec = s % 60
  return String.format("%02d:%02d:%02d", h, m, sec)
}

snippets.C0014:
// Caso: Validar paréntesis/corchetes/llaves | Nivel: Intermedio | Categoría: Stacks
fun solve(s: String): Boolean {
  val st = ArrayDeque<Char>()
  val pairs = mapOf(')' to '(', ']' to '[', '}' to '{')
  for (ch in s) {
    if (ch == '(' || ch == '[' || ch == '{') st.addLast(ch)
    else if (ch == ')' || ch == ']' || ch == '}') {
      val top = if (st.isEmpty()) null else st.removeLast()
      if (top != pairs[ch]) return false
    }
  }
  return st.isEmpty()
}

