}

snippets.C0017:
// Caso: Two Sum | Nivel: Intermedio | Categoría: Map/Hash
fun solve(arr: IntArray, target: Int): IntArray? {
  val seen = HashMap<Int, Int>()
  for (i in arr.indices) {
    val need = target - arr[i]
    val j = seen[need]
    if (j != null) return intArrayOf(j, i)
    seen[arr[i]] = i
  }
  return null
}

