fun solve(arr: IntArray): IntArray {
  val seen = HashSet<Int>()
  val out = ArrayList<Int>()
  for (x in arr) if (seen.add(x)) out.add(x)
  return out.toIntArray()
}

snippets.C0019:
// Caso: Rotar arreglo k | Nivel: Intermedio | Categoría: Arrays
fun solve(arr: IntArray, k: Int): IntArray {
  val n = arr.size
  if (n == 0) return intArrayOf()
  val r = ((k % n) + n) % n
  val out = IntArray(n)
  for (i in 0 until n) out[(i + r) % n] = arr[i]
  return out
}

