snippets.C0021:
// Caso: Búsqueda binaria | Nivel: Intermedio | Categoría: Búsqueda
fun solve(arr: IntArray, target: Int): Int {
  var lo = 0
  var hi = arr.size - 1
  while (lo <= hi) {
    val mid = (lo + hi) / 2
    val v = arr[mid]
    if (v == target) return mid
    if (v < target) lo = mid + 1 else hi = mid - 1
  }
  return -1
}

snippets.C0022:
// Caso: Bubble sort | Nivel: Intermedio | Categoría: Ordenamiento
fun solve(arr: IntArray): IntArray {
  val a = arr.clone()
  for (i in a.indices) {
    for (j in 0 until a.size - 1 - i) {
      if (a[j] > a[j+1]) { val t=a[j]; a[j]=a[j+1]; a[j+1]=t }
    }
  }
  return a
}

