fun solve(n: Int): List<String> {
  val out = ArrayList<String>()
  for (i in 1..n) {
    var s = ""
    if (i % 3 == 0) s += "Fizz"
    if (i % 5 == 0) s += "Buzz"
    out.add(if (s.isEmpty()) i.toString() else s)
  }
  return out
}

