// Caso: Validar RUT chileno | Nivel: Intermedio | Categoría: Validación
fun solve(rut: String): Boolean {
  val clean = rut.replace(".", "").replace("-", "").replace(" ", "").uppercase()
  if (clean.length < 2) return false

  val body = clean.dropLast(1)
  val dv = clean.last()

  if (!body.all { it.isDigit() }) return false

  var sum = 0
  var mul = 2
  for (i in body.length - 1 downTo 0) {
    val d = body[i].code - '0'.code
    sum += d * mul
    mul = if (mul == 7) 2 else (mul + 1)
  }

  val mod = 11 - (sum % 11)
  val dvCalc = when (mod) {
    11 -> '0'
    10 -> 'K'
    else -> ('0'.code + mod).toChar()
  }
  return dv == dvCalc
