import com.fasterxml.jackson.databind.ObjectMapper
import com.networknt.schema.JsonSchemaFactory
import com.networknt.schema.SpecVersion
import com.networknt.schema.ValidationMessage

fun solve() {
  val schemaJson = """{"type":"object","required":["name","qty"],"properties":{"name":{"type":"string"},"qty":{"type":"integer","minimum":1}}}"""
  val dataJson = """{"name":"Item","qty":1}"""
  val om = ObjectMapper()
  val f = JsonSchemaFactory.getInstance(SpecVersion.VersionFlag.V202012)
  val schema = f.getSchema(om.readTree(schemaJson))
  val errors = schema.validate(om.readTree(dataJson)).map { it.message }
  println(errors.isEmpty()); println(errors)
}

