// C0680 · Uso de teclado (keydown/atajos) (Intermedio, UI/Entrada)
// Kotlin: lectura básica por stdin (requiere Enter)
fun solve() {
  println("Escribe una tecla y Enter (w/a/s/d, q):")
  while (true) {
    val line = readLine() ?: break
    if (line.isEmpty()) continue
    val k = line[0].lowercaseChar()
    if (k == 'q') break
    if (k == 'w') println("Mover: arriba")
    if (k == 's') println("Mover: abajo")
    if (k == 'a') println("Mover: izquierda")
    if (k == 'd') println("Mover: derecha")
  }
}
